 72→//-----------------------------------------------------------------
 73→// Executes a link, attached to a trigger.
 74→// Toggles all walls linked to the switch.
 75→// Opens doors, Blasts blast walls, turns off illusions.
 76→void do_link(int8_t trigger_num)
 77→{
 78→	int i;
 79→
 80→	mprintf((0, "Door link!\n"));
 81→
 82→	if (trigger_num != -1) 
 83→	{
 84→		for (i = 0; i < Triggers[trigger_num].num_links; i++) 
 85→		{
 86→			wall_toggle(&Segments[Triggers[trigger_num].seg[i]], Triggers[trigger_num].side[i]);
 87→			mprintf((0, " trigger_num %d : seg %d, side %d\n",
 88→				trigger_num, Triggers[trigger_num].seg[i], Triggers[trigger_num].side[i]));
 89→		}
 90→	}
 91→}
