111→void do_il_on(int8_t trigger_num)
112→{
113→#ifdef USE_OX_BRIDGE
114→	if (cd_ox_is_ready()) {
115→		static int seg_side_reg = 0;
116→		if (!seg_side_reg) {
117→			seg_side_reg = 1;
118→			cd_ox_register_switch_seg_side_effect(
119→				/* fetch_trigger_seg_sides */
120→				[](int tnum, int32_t* out, int* out_len) {
121→					int n = Triggers[tnum].num_links;
122→					out[0] = n;
123→					for (int j = 0; j < n; j++) {
124→						out[1 + j * 2] = Triggers[tnum].seg[j];
125→						out[1 + j * 2 + 1] = Triggers[tnum].side[j];
126→					}
127→					*out_len = 1 + n * 2;
128→				});
129→		}
130→		cd_ox_do_il_on(trigger_num);
131→		return;
132→	}
133→#endif
134→	int i;
135→
136→	mprintf((0, "Illusion ON\n"));
137→
138→	if (trigger_num != -1)
139→	{
140→		for (i = 0; i < Triggers[trigger_num].num_links; i++)
141→		{
142→			wall_illusion_on(&Segments[Triggers[trigger_num].seg[i]], Triggers[trigger_num].side[i]);
143→			mprintf((0, " trigger_num %d : seg %d, side %d\n",
144→				trigger_num, Triggers[trigger_num].seg[i], Triggers[trigger_num].side[i]));
145→		}
146→	}
147→}
