166→int check_trigger_sub(int trigger_num, int pnum)
167→{
168→	if (pnum == Player_num) 
169→	{
170→		if (Triggers[trigger_num].flags & TRIGGER_SHIELD_DAMAGE) 
171→		{
172→			Players[Player_num].shields -= Triggers[trigger_num].value;
173→			mprintf((0, "BZZT!\n"));
174→		}
175→
176→		if (Triggers[trigger_num].flags & TRIGGER_EXIT) 
177→		{
178→			start_endlevel_sequence();
179→			mprintf((0, "WOOHOO! (leaving the mine!)\n"));
180→		}
181→
182→		if (Triggers[trigger_num].flags & TRIGGER_SECRET_EXIT) 
183→		{
184→			if (Newdemo_state == ND_STATE_RECORDING)		// stop demo recording
185→				Newdemo_state = ND_STATE_PAUSED;
186→
187→			Fuelcen_control_center_destroyed = 0;
188→			mprintf((0, "Exiting to secret level\n"));
189→#ifdef NETWORK
190→			if (Game_mode & GM_MULTI)
191→				multi_send_endlevel_start(1);
192→#endif
193→#ifdef NETWORK
194→			if (Game_mode & GM_NETWORK)
195→				network_do_frame(1, 1);
196→#endif
197→			gr_palette_fade_out(gr_palette, 32, 0);
198→			PlayerFinishedLevel(1);		//1 means go to secret level
199→			return 1;
200→		}
201→
202→		if (Triggers[trigger_num].flags & TRIGGER_ENERGY_DRAIN) 
203→		{
204→			Players[Player_num].energy -= Triggers[trigger_num].value;
205→			mprintf((0, "SLURP!\n"));
206→		}
207→	}
208→
209→	if (Triggers[trigger_num].flags & TRIGGER_CONTROL_DOORS) 
210→	{
211→		mprintf((0, "D"));
212→		do_link(trigger_num);
213→	}
214→
215→	if (Triggers[trigger_num].flags & TRIGGER_MATCEN) 
216→	{
217→		if (!(Game_mode & GM_MULTI) || (Game_mode & GM_MULTI_ROBOTS))
218→			do_matcen(trigger_num);
219→	}
220→
221→	if (Triggers[trigger_num].flags & TRIGGER_ILLUSION_ON) 
222→	{
223→		mprintf((0, "I"));
224→		do_il_on(trigger_num);
225→	}
226→
227→	if (Triggers[trigger_num].flags & TRIGGER_ILLUSION_OFF) 
228→	{
229→		//		Triggers[trigger_num].time = TRIGGER_DELAY_DOOR;
230→		mprintf((0, "i"));
231→		do_il_off(trigger_num);
232→	}
233→	return 0;
234→}
