236→//-----------------------------------------------------------------
237→// Checks for a trigger whenever an object hits a trigger side.
238→void check_trigger(segment* seg, short side, short objnum)
239→{
240→	int wall_num, trigger_num, ctrigger_num;
241→	segment* csegp;
242→	short cside;
243→
244→	//	mprintf(0,"T");
245→
246→	if (objnum == Players[Player_num].objnum) 
247→	{
248→
249→		//		if ( Newdemo_state == ND_STATE_RECORDING )
250→		//			newdemo_record_trigger( seg-Segments, side, objnum );
251→
252→		if (Newdemo_state == ND_STATE_PLAYBACK)
253→			return;
254→
255→		wall_num = seg->sides[side].wall_num;
256→		if (wall_num == -1) return;
257→
258→		trigger_num = Walls[wall_num].trigger;
259→
260→		if (trigger_num == -1)
261→			return;
262→
263→		if (check_trigger_sub(trigger_num, Player_num))
264→			return;
265→
266→		if (Triggers[trigger_num].flags & TRIGGER_ONE_SHOT) 
267→		{
268→			Triggers[trigger_num].flags &= ~TRIGGER_ON;
269→
270→			csegp = &Segments[seg->children[side]];
271→			cside = find_connect_side(seg, csegp);
272→			Assert(cside != -1);
273→
274→			wall_num = csegp->sides[cside].wall_num;
275→			if (wall_num == -1) return;
276→
277→			ctrigger_num = Walls[wall_num].trigger;
278→
279→			Triggers[ctrigger_num].flags &= ~TRIGGER_ON;
280→		}
281→#ifndef SHAREWARE
282→#ifdef NETWORK
283→		if (Game_mode & GM_MULTI)
284→			multi_send_trigger(trigger_num);
285→#endif
286→#endif
287→	}
288→}
