112→//turns lighting on.  returns true if lights were actually turned on. (they
113→//would not be if they had previously been shot out).
114→int do_light_on(int8_t trigger_num)
115→{
116→	int i,ret=0;
117→
118→	mprintf((0, "Lighting on!\n"));
119→
120→	if (trigger_num != -1) 
121→	{
122→		for (i=0;i<Triggers[trigger_num].num_links;i++) 
123→		{
124→			int segnum,sidenum;
125→			segnum = Triggers[trigger_num].seg[i];
126→			sidenum = Triggers[trigger_num].side[i];
127→
128→			//check if tmap2 casts light before turning the light on.  This
129→			//is to keep us from turning on blown-out lights
130→			if (TmapInfo[Segments[segnum].sides[sidenum].tmap_num2 & 0x3fff].lighting)
131→			{
132→				ret |= add_light(segnum, sidenum); 		//any light sets flag
133→				enable_flicker(segnum, sidenum);
134→			}
135→		}
136→	}
137→
138→	return ret;
139→}
