170→// Unlocks all doors linked to the switch.
171→void do_unlock_doors(int8_t trigger_num)
172→{
173→#ifdef USE_OX_BRIDGE
174→	if (cd_ox_is_ready()) {
175→		static int sw_reg = 0;
176→		if (!sw_reg) {
177→			sw_reg = 1;
178→			cd_ox_register_switch_effects(
179→				/* fetch_trigger_links */
180→				[](int tnum, int32_t* out, int* out_len) {
181→					int n = Triggers[tnum].num_links;
182→					out[0] = n;
183→					for (int j = 0; j < n; j++)
184→						out[1 + j] = Segments[Triggers[tnum].seg[j]].sides[Triggers[tnum].side[j]].wall_num;
185→					*out_len = 1 + n;
186→				},
187→				/* lock_wall_door */
188→				[](int wnum) {
189→					Walls[wnum].flags |= WALL_DOOR_LOCKED;
190→				},
191→				/* unlock_wall_door */
192→				[](int wnum) {
193→					Walls[wnum].flags &= ~WALL_DOOR_LOCKED;
194→					Walls[wnum].keys = KEY_NONE;
195→				},
196→				/* get_num_triggers */
197→				[]() -> int {
198→					return Num_triggers;
199→				},
200→				/* get_num_walls */
201→				[]() -> int {
202→					return Num_walls;
203→				},
204→				/* set_wall_flag_wall_switch */
205→				[](int wnum) {
206→					Walls[wnum].flags |= WALL_WALL_SWITCH;
207→				});
208→		}
209→		cd_ox_do_unlock_doors(trigger_num);
210→		return;
211→	}
212→#endif
213→	int i;
214→
215→	mprintf((0, "Door unlock!\n"));
216→
217→	if (trigger_num != -1)
218→	{
219→		for (i=0;i<Triggers[trigger_num].num_links;i++)
220→		{
221→			Walls[Segments[Triggers[trigger_num].seg[i]].sides[Triggers[trigger_num].side[i]].wall_num].flags &= ~WALL_DOOR_LOCKED;
222→			Walls[Segments[Triggers[trigger_num].seg[i]].sides[Triggers[trigger_num].side[i]].wall_num].keys = KEY_NONE;
223→  		}
224→  	}
225→}
