234→#endif
235→	int i, t;
236→
237→	for (t=0; t<Num_triggers; t++)
238→	{
239→		for (i=0; i<Triggers[t].num_links; i++)
240→		{
241→			if (Segments[Triggers[t].seg[i]].sides[Triggers[t].side[i]].wall_num == wall_num) {
242→				mprintf((0, "Wall #%i is keyed to trigger #%i, link #%i\n", wall_num, t, i));
243→				return t;
244→			}
245→	  	}
246→	}
247→
248→	return -1;
249→}
