291→// Changes walls pointed to by a trigger. returns true if any walls changed
292→int do_change_walls(int8_t trigger_num)
293→{
294→	int i,ret=0;
295→
296→	mprintf((0, "Wall remove!\n"));
297→
298→	if (trigger_num != -1) 
299→	{
300→		for (i=0;i<Triggers[trigger_num].num_links;i++) 
301→		{
302→			segment *segp,*csegp;
303→			short side,cside;
304→			int new_wall_type;
305→
306→			segp = &Segments[Triggers[trigger_num].seg[i]];
307→			side = Triggers[trigger_num].side[i];
308→
309→			csegp = &Segments[segp->children[side]];
310→			cside = find_connect_side(segp, csegp);
311→			Assert(cside != -1);
312→
313→			//segp->sides[side].wall_num = -1;
314→			//csegp->sides[cside].wall_num = -1;
315→
316→			switch (Triggers[trigger_num].type)
317→			{
318→				case TT_OPEN_WALL:		new_wall_type = WALL_OPEN; break;
319→				case TT_CLOSE_WALL:		new_wall_type = WALL_CLOSED; break;
320→				case TT_ILLUSORY_WALL:	new_wall_type = WALL_ILLUSION; break;
321→			}
322→
