void cd_ox_register_gameseq_effects(
    cd_effect_gs_fetch_bash_to_shield_data_fn fetch_bash_data,
    cd_effect_gs_write_bash_to_shield_fn write_bash_data)
{
    g_effect_gs_fetch_bash_to_shield_data = fetch_bash_data;
