    Store_field(v_packed, 1, Val_long(lfup_y));
    Store_field(v_packed, 2, Val_long(lfup_z));
    Store_field(v_packed, 3, Val_long(bp_x));
    Store_field(v_packed, 4, Val_long(bp_y));
