void bash_to_shield(int i, const char* s)
{
#ifdef USE_OX_BRIDGE
	if (cd_ox_is_ready()) {
		/* Register gameseq effects on first call */
		static int gs_reg = 0;
		if (!gs_reg) {
			gs_reg = 1;
